from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["autonomous-ia-work-session-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>Autonomous IA Work Session</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#173766,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px}button,input,textarea,select{font:inherit;border-radius:16px;border:1px solid var(--line);background:#0b1220;color:var(--text);padding:12px}button{background:linear-gradient(135deg,#0284c7,#38bdf8);border:none;color:#02101b;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}textarea{width:100%;min-height:90px}.packet{border-left:4px solid #38bdf8;padding:9px 10px;background:#081226;border-radius:14px}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}}</style></head><body><div class="page"><section class="panel"><h1>Autonomous IA Work Session</h1><p class="muted">God Mode cria pacotes para IAs enquanto o Oner está ocupado. Envio/captura em providers privados continua manual/gated.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="location.href='/app/god-mode-self-diagnosis'" class="dark">Self Diagnosis</button><button onclick="dashboard()">Dashboard</button><button onclick="packets()">Packets</button></div></section><section class="panel"><h2>Criar sessão</h2><input id="sessionTitle" style="width:100%" value="God Mode self-fix while Oner is busy"/><textarea id="sessionGoal">Continuar a melhorar o God Mode para instalação real no PC, auto-diagnóstico, geração de PR plans e evolução controlada, sem exigir interação do Oner enquanto está a conduzir.</textarea><button onclick="createSession()">Criar sessão IA</button></section><section class="panel"><h2>Criar packet manual</h2><input id="sessionId" style="width:100%" placeholder="ia-work-session-..."/><div class="grid"><select id="provider"><option>chatgpt</option><option>claude</option><option>gemini</option><option>praison</option><option>ruflo</option><option>manual_ai</option></select><input id="project" value="GOD_MODE"/></div><input id="taskTitle" style="width:100%" value="Analyze next God Mode self-fix"/><textarea id="taskGoal">Analisa a próxima lacuna do God Mode e devolve plano de implementação seguro, ficheiros afetados, riscos e testes.</textarea><textarea id="context">Sem tokens, sem cookies, sem deploy, sem merge automático. Oner está ocupado; separar ações seguras das que exigem aprovação.</textarea><div class="buttons"><button onclick="createPacket()">Criar packet</button><button onclick="createFromDiagnosis()">Criar packets do self-diagnosis</button></div></section><section class="panel"><h2>Resposta IA</h2><input id="packetId" style="width:100%" placeholder="ia-work-packet-..."/><textarea id="responseText">Cole aqui a resposta da IA quando existir.</textarea><div class="buttons"><button onclick="importResponse()">Importar resposta</button><button onclick="convertTasks()">Converter para tarefas</button><button onclick="launcher()">Contrato provider</button></div></section><section class="panel"><h2>Packets</h2><div id="items" class="grid"></div></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function esc(s){return String(s??'').replaceAll('<','&lt;')}function show(x){qs('#out').textContent=JSON.stringify(x,null,2);render(x)}function render(x){const items=x?.work_packets||x?.work_packet?[x.work_packet]:x?.dashboard?.work_packets||[];qs('#items').innerHTML=(Array.isArray(items)?items:[]).slice(0,24).map(it=>`<div class="packet" onclick="qs('#packetId').value='${esc(it.work_packet_id)}'"><b>${esc(it.provider)}</b> ${esc(it.status)}<br>${esc(it.task_title)}<br><span class="muted">${esc(it.work_packet_id)}</span></div>`).join('')}async function dashboard(){show(await api('/api/autonomous-ia-work-session/dashboard'))}async function packets(){show(await api('/api/autonomous-ia-work-session/packets?limit=150'))}async function createSession(){const x=await api('/api/autonomous-ia-work-session/create-session',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({title:qs('#sessionTitle').value,goal:qs('#sessionGoal').value,project_id:'GOD_MODE',operator_mode:'oner_busy_safe'})});qs('#sessionId').value=x?.work_session?.work_session_id||'';show(x)}async function createPacket(){show(await api('/api/autonomous-ia-work-session/create-work-packet',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({work_session_id:qs('#sessionId').value,provider:qs('#provider').value,task_title:qs('#taskTitle').value,task_goal:qs('#taskGoal').value,context:qs('#context').value,target_project:qs('#project').value})}))}async function createFromDiagnosis(){show(await api('/api/autonomous-ia-work-session/create-packets-from-self-diagnosis',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({work_session_id:qs('#sessionId').value,providers:['chatgpt','claude','gemini'],limit:5})}))}async function importResponse(){show(await api('/api/autonomous-ia-work-session/import-response',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({work_packet_id:qs('#packetId').value,response_text:qs('#responseText').value,provider:qs('#provider').value})}))}async function convertTasks(){show(await api('/api/autonomous-ia-work-session/convert-response-to-tasks',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({work_packet_id:qs('#packetId').value})}))}async function launcher(){show(await api('/api/autonomous-ia-work-session/create-provider-launcher-contract',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({work_packet_id:qs('#packetId').value})}))}dashboard()</script></body></html>
"""


@router.get('/app/autonomous-ia-work-session', response_class=HTMLResponse)
async def autonomous_ia_work_session_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/ia-work-operator', response_class=HTMLResponse)
async def ia_work_operator_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
